export default Dictionary;

export const normalizeQuery = (text: string, lang?: string): string => {
  if (!text) return "";

  // 1. Unicode Normalization (NFC) - Critical for iOS NFD (decomposed) compatibility
  // This ensures that 'e' + '´' becomes 'é' before processing.
  let res = text.normalize('NFC');

  // 2. Aggressively strip non-visible/control/zero-width characters that iOS keyboards inject
  // We keep essential formatting like spaces but remove artifacts from auto-correct and predictive text.
  res = res.replace(/[\u0000-\u001F\u007F-\u009F\u200B-\u200D\u2028\u2029\uFEFF]/g, "");

  // 3. Lowercase and standard trim
  res = res.trim().toLowerCase();

  // 4. iOS Smart Punctuation & Typographic variances
  // Handles smart quotes, various apostrophes, and non-breaking spaces
  res = res
    .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035\u02BB\u02BC]/g, "'") 
    .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
    .replace(/\u2013/g, "-")
    .replace(/\u2014/g, "--")
    .replace(/[\u00A0\u202F]/g, " ");

  // 5. Philological Normalization (Language Specific)
  // We use standard substitutions for consistent search mapping in the lexicon archive.
  if (lang === 'German') {
    res = res
      .replace(/ä/g, 'ae')
      .replace(/ö/g, 'oe')
      .replace(/ü/g, 'ue')
      .replace(/ß/g, 'ss');
  } else if (lang === 'Uzbek') {
    // Normalize variants of the okina/apostrophe used in Uzbek Latin to a standard straight quote
    res = res.replace(/[‘’`‘]/g, "'");
  }

  return res.trim();
};

