    return { title: "Lexical Continuity", fact: "Language is the living vessel of human history." };
  }
}

/**
 * Fisher-Yates shuffle algorithm to randomize quiz options.
 */
function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

/**
 * Arena Quiz Generation
 */
export async function generateQuiz(entries: LexicalEntry[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const context = entries.map(e => `${e.term} -> ${e.mainTranslation}`).join(", ");
  const prompt = `Create a 3-choice quiz for the following lexicon entries: ${context}. Output: JSON Array.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            },
            required: ["question", "correctAnswer", "options", "explanation"]
          }
        }
      }
    });

    const cleaned = cleanJsonResponse(response.text || "[]");
    const questions = JSON.parse(cleaned);
    return questions.map((q: any) => ({
      ...q,
      options: shuffleArray(q.options || [])
    }));
  } catch (err) {
    return [];
  }
}
